#include <bits/stdc++.h>
using namespace std;

int fa[30005], sz[30005], d[30005];

int find(int x)
{
    if(x == fa[x]) return x;
    int r = find(fa[x]);
    d[x] += d[fa[x]];
    return fa[x] = r;
}

void merge(int x, int y)
{
    x = find(x), y = find(y);
    d[x] = sz[y];
    fa[x] = y;
    sz[y] += sz[x];
}

int main()
{
    int m;
    char c;
    cin >> m;
    for(int i = 1; i <= 30000; i++)
        fa[i] = i;
    fill(sz, sz + 30000 + 1, 1);
    for(int i = 1; i <= m; i++)
    {
        int x, y;
        cin >> c >> x >> y;
        if(c == 'M')
            merge(x, y);
        else{
            if(find(x) != find(y))
                cout << -1 << endl;
            else
                cout << abs(d[x] - d[y]) - 1 << endl;
        }
    }
    return 0;
}
